 ex_orders_get_java java Get order details (Java) import com.acme.api.AcmeClient;
import com.acme.api.models.Order;
import java.util.Arrays;

public class GetOrderExample {
    public static void main(String[] args) {
        AcmeClient client = new AcmeClient.Builder()
            .setApiKey("sk_test_123")
            .build();

        Order order = client.orders().get("ord_987654321", Arrays.asList("items"));
        System.out.println(order.getId() + " status=" + order.getStatus());
    }
}
 ex_projects_create_node projects_create node_js Create a new project const Acme = require("acme-api");

const client = new Acme.Client({ apiKey: "sk_test_123" });

async function main() {
  const project = await client.projects.create({
    name: "My First Project",
    metadata: { env: "sandbox" }
  });

  console.log(project.id, project.name);
}

main().catch(console.error);
